import requests, re, base64, struct

URL='http://crypto.chal.csaw.io:5000'

# Minimal SHA1 with custom state
class SHA1:
    def __init__(self, h0=0x67452301,h1=0xEFCDAB89,h2=0x98BADCFE,h3=0x10325476,h4=0xC3D2E1F0,message_byte_length=0):
        self.h0=h0; self.h1=h1; self.h2=h2; self.h3=h3; self.h4=h4
        self.message_byte_length=message_byte_length
        self._unprocessed=b''
    def _left_rotate(self,n,b):
        return ((n<<b)|(n>>(32-b))) & 0xffffffff
    def _process_chunk(self,chunk):
        w=[0]*80
        for i in range(16):
            w[i]=struct.unpack('>I',chunk[i*4:(i+1)*4])[0]
        for i in range(16,80):
            w[i]=self._left_rotate(w[i-3]^w[i-8]^w[i-14]^w[i-16],1)
        a,b,c,d,e=self.h0,self.h1,self.h2,self.h3,self.h4
        for i in range(80):
            if i<20:
                f=(b&c)|((~b)&d); k=0x5A827999
            elif i<40:
                f=b^c^d; k=0x6ED9EBA1
            elif i<60:
                f=(b&c)|(b&d)|(c&d); k=0x8F1BBCDC
            else:
                f=b^c^d; k=0xCA62C1D6
            temp=(self._left_rotate(a,5)+f+e+k+w[i]) & 0xffffffff
            e=d; d=c; c=self._left_rotate(b,30); b=a; a=temp
        self.h0=(self.h0+a)&0xffffffff
        self.h1=(self.h1+b)&0xffffffff
        self.h2=(self.h2+c)&0xffffffff
        self.h3=(self.h3+d)&0xffffffff
        self.h4=(self.h4+e)&0xffffffff
    def update(self,data:bytes):
        self._unprocessed += data
        while len(self._unprocessed)>=64:
            self._process_chunk(self._unprocessed[:64])
            self._unprocessed=self._unprocessed[64:]
            self.message_byte_length += 64
    def digest(self):
        ml=self.message_byte_length + len(self._unprocessed)
        data=self._unprocessed + b'\x80'
        data += b'\x00'*((56-(ml+1)%64)%64)
        data += struct.pack('>Q', ml*8)
        for i in range(0,len(data),64):
            self._process_chunk(data[i:i+64])
        return struct.pack('>IIIII',self.h0,self.h1,self.h2,self.h3,self.h4)
    def hexdigest(self):
        return self.digest().hex()

def sha1_pad(msg_len):
    pad=b'\x80'+b'\x00'*((56-(msg_len+1)%64)%64)+struct.pack('>Q',msg_len*8)
    return pad

def parse_mac(hexmac):
    return struct.unpack('>IIIII', bytes.fromhex(hexmac))

def to_escaped(bs:bytes):
    out=''
    for b in bs:
        out += f'\\x{b:02x}'
    return out

